package ql.src.org.apache.hadoop.hive.ql.processors;

public class CommandProcessorResponse { private int responseCode ; private String errorMessage ; private String SQLState ; private Schema resSchema ; public CommandProcessorResponse ( int responseCode ) { this ( responseCode , null , null ) ; } public CommandProcessorResponse ( int responseCode , String errorMessage , String SQLState ) { this ( responseCode , errorMessage , SQLState , null ) ; } public CommandProcessorResponse ( int responseCode , String errorMessage , String SQLState , Schema schema ) { this . responseCode = responseCode ; this . errorMessage = errorMessage ; this . SQLState = SQLState ; this . resSchema = schema ; } public int getResponseCode ( ) { return responseCode ; } public String getErrorMessage ( ) { return errorMessage ; } public String getSQLState ( ) { return SQLState ; } public Schema getSchema ( ) { return resSchema ; } }